import React from 'react';
import { Card, Stack, Text, Heading, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent(props: Props) {
  const {
    city = 'Unknown City',
    temperature = 0,
    condition = 'Sunny',
    humidity = 0,
    windSpeed = 0,
    unit = 'C',
    forecast = [],
  } = props;

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack gap={24}>
        {/* City & Condition Header */}
        <Stack gap={4} align="center">
          <Heading level={2}>{city ?? 'Unknown City'}</Heading>
          <Text variant="bodyLarge" color="var(--ggui-color-neutral-500, #6b7280)">
            {condition ?? 'N/A'}
          </Text>
        </Stack>

        {/* Temperature Display */}
        <Box paddingY={16}>
          <Text size="4xl" weight="bold" align="center">
            {temperature}°{unit}
          </Text>
        </Box>

        {/* Stats Strip */}
        <Stack direction="horizontal" justify="around">
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
              Humidity
            </Text>
            <Text variant="label">{humidity}%</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
              Wind
            </Text>
            <Text variant="label">{windSpeed} km/h</Text>
          </Stack>
        </Stack>

        <Divider margin={8} />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="center" gap={8}>
          {forecast.map((item, index) => (
            <Stack key={index} align="center" gap={8}>
              <Text variant="overline">{item.day ?? '-'}</Text>
              <Text size="xl">{item.icon ?? '☁️'}</Text>
              <Stack gap={2} align="center">
                <Text variant="bodySmall" weight="semibold">
                  {item.high}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">
                  {item.low}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Card, Stack, Text, Heading, Button, Input, TextArea, RadioGroup, Checkbox, Divider, Box, Spacer } from '@ggui-ai/design/primitives';

interface Props {
  featureOptions?: string[];
  satisfactionLabels?: string[];
}

interface FormData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

export default function GeneratedComponent({
  featureOptions = ["Dashboard Analytics", "Team Collaboration", "API Integration", "Custom Workflows", "Mobile App", "AI Assistance"],
  satisfactionLabels = ["Very Unsatisfied", "Unsatisfied", "Neutral", "Satisfied", "Very Satisfied"],
}: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<FormData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canProceed = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && isEmailValid(formData.email);
    if (step === 2) return formData.satisfaction !== '';
    return true;
  }, [step, formData]);

  const updateField = (key: keyof FormData, value: any) => {
    setFormData((prev) => ({ ...prev, [key]: value }));
  };

  const toggleFeature = (feature: string) => {
    setFormData((prev) => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter((f) => f !== feature)
        : [...prev.features, feature],
    }));
  };

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap={16}>
            <Heading level={3}>Your Information</Heading>
            <Input label="Name" required value={formData.name} onChange={(v) => updateField('name', v)} />
            <Input label="Email" required value={formData.email} onChange={(v) => updateField('email', v)} error={formData.email && !isEmailValid(formData.email) ? 'Invalid email format' : undefined} />
          </Stack>
        );
      case 2:
        return (
          <RadioGroup
            label="Satisfaction Rating"
            value={formData.satisfaction}
            onChange={(v) => updateField('satisfaction', v)}
            options={satisfactionLabels.map((l, i) => ({ label: l, value: String(i + 1) }))}
          />
        );
      case 3:
        return (
          <Stack gap={8}>
            <Heading level={3}>Features of Interest</Heading>
            {featureOptions.map((opt) => (
              <Checkbox key={opt} label={opt} checked={formData.features.includes(opt)} onChange={() => toggleFeature(opt)} />
            ))}
          </Stack>
        );
      case 4:
        return (
          <Stack gap={16}>
            <Heading level={3}>Review & Comments</Heading>
            <Card padding={16} border={true}>
              <Text variant="label">Name: {formData.name}</Text>
              <Text variant="label">Email: {formData.email}</Text>
              <Text variant="label">Satisfaction: {satisfactionLabels[Number(formData.satisfaction) - 1]}</Text>
              <Text variant="label">Features: {formData.features.join(', ') || 'None'}</Text>
            </Card>
            <TextArea label="Comments" value={formData.comments} onChange={(v) => updateField('comments', v)} maxLength={500} showCount />
          </Stack>
        );
      default:
        return null;
    }
  };

  return (
    <Container maxWidth="sm" padding={24}>
      <Card padding={24} shadow="md">
        <Stack gap={24}>
          <Stack gap={4}>
            <Heading level={2}>Customer Survey</Heading>
            <Text variant="caption">Step {step} of 4</Text>
          </Stack>

          <Box paddingY={8}>
            {renderStep()}
          </Box>

          <Divider />

          <Stack direction="horizontal" justify="between">
            <Button variant="secondary" disabled={step === 1} onClick={() => setStep((s) => s - 1)}>Back</Button>
            {step < 4 ? (
              <Button disabled={!canProceed} onClick={() => setStep((s) => s + 1)}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => console.log('Submitted', formData)}>Submit Survey</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState } from 'react';
import { Container, Stack, Card, Text, Heading, Button, Input, Select, Box, Badge, Avatar, Spacer } from '@ggui-ai/design/primitives';

interface Task {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  column: string;
  dueDate?: string;
}

interface Props {
  tasks: Array<Task>;
  columns: Array<{ id: string; name: string }>;
  onTaskUpdate?: (payload: { action: 'move' | 'edit' | 'create'; taskId?: string; data: any }) => void;
}

export default function KanbanBoard({ tasks: initialTasks, columns, onTaskUpdate }: Props) {
  const [tasks, setTasks] = useState<Task[]>(initialTasks);
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  const updateTask = (id: string, updates: Partial<Task>) => {
    const updated = tasks.map(t => t.id === id ? { ...t, ...updates } : t);
    setTasks(updated);
    onTaskUpdate?.({ action: 'move', taskId: id, data: updates });
  };

  const addTask = (columnId: string) => {
    const newTask: Task = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      assignee: '??',
      column: columnId,
    };
    setTasks([...tasks, newTask]);
    setIsAdding(null);
    setNewTaskTitle('');
    onTaskUpdate?.({ action: 'create', data: newTask });
  };

  const getPriorityVariant = (p: string) => {
    switch (p) {
      case 'high': return 'error';
      case 'medium': return 'warning';
      default: return 'info';
    }
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack direction="horizontal" align="start" gap={16}>
        {columns.map(col => {
          const colTasks = tasks.filter(t => t.column === col.id);
          return (
            <Box key={col.id} background="var(--ggui-color-surfaceVariant)" padding={16} borderRadius={8} style={{ width: 320 }}>
              <Stack direction="horizontal" align="center" justify="between" gap={8}>
                <Heading level={3}>{col.name}</Heading>
                <Badge variant="secondary">{colTasks.length}</Badge>
              </Stack>
              <Spacer size={16} />
              <Stack gap={12}>
                {colTasks.map(t => (
                  <Card key={t.id} shadow="sm" padding={12}>
                    <Text variant="label">{t.title}</Text>
                    <Spacer size={8} />
                    <Stack direction="horizontal" justify="between" align="center">
                      <Badge variant={getPriorityVariant(t.priority)}>{t.priority}</Badge>
                      <Avatar name={t.assignee} size={24} />
                    </Stack>
                    <Spacer size={8} />
                    <Select 
                      label="Move task"
                      value={t.column}
                      onChange={(v) => updateTask(t.id, { column: v })}
                      options={columns.map(c => ({ value: c.id, label: `Move to ${c.name}` }))}
                    />
                  </Card>
                ))}
              </Stack>
              <Spacer size={16} />
              {isAdding === col.id ? (
                <Stack gap={8}>
                  <Input label="Task title" value={newTaskTitle} onChange={setNewTaskTitle} placeholder="e.g. Design landing page" />
                  <Select 
                    label="Priority"
                    value={newTaskPriority} 
                    onChange={(v: any) => setNewTaskPriority(v)} 
                    options={[
                      { value: 'low', label: 'Low' }, 
                      { value: 'medium', label: 'Medium' }, 
                      { value: 'high', label: 'High' }
                    ]} 
                  />
                  <Button onClick={() => addTask(col.id)}>Submit</Button>
                </Stack>
              ) : (
                <Button variant="ghost" onClick={() => setIsAdding(col.id)}>+ Add Task</Button>
              )}
            </Box>
          );
        })}
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { Container, Card, Stack, Box, Text, Heading, Input, Divider } from '@ggui-ai/design/primitives';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  elements: ElementData[];
}

const CATEGORY_COLORS: Record<string, string> = {
  'nonmetal': 'var(--ggui-color-primary-200, #bae6fd)',
  'noble-gas': 'var(--ggui-color-info-200, #a5f3fc)',
  'alkali-metal': 'var(--ggui-color-warning-200, #fde68a)',
  'alkaline-earth-metal': 'var(--ggui-color-warning-100, #fef3c7)',
  'transition-metal': 'var(--ggui-color-primary-100, #e0f2fe)',
  'halogen': 'var(--ggui-color-success-200, #bbf7d0)',
  'default': 'var(--ggui-color-neutral-200, #e5e7eb)',
};

export default function GeneratedComponent(props: Props) {
  const { elements = [] } = props;
  const [search, setSearch] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    return elements.filter(
      (el) =>
        el.name?.toLowerCase().includes(search.toLowerCase()) ||
        el.symbol?.toLowerCase().includes(search.toLowerCase())
    );
  }, [elements, search]);

  const categories = Array.from(new Set(elements.map((el) => el.category || 'default')));

  return (
    <Container maxWidth="3xl" padding={24}>
      <Stack gap={24}>
        <Heading level={1}>Periodic Table</Heading>

        <Input 
          type="search" 
          label="Search Elements" 
          placeholder="Search by name or symbol..." 
          value={search} 
          onChange={setSearch} 
        />

        <Box 
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: '4px',
          }}
        >
          {elements.map((el, i) => {
            const isVisible = filteredElements.includes(el);
            return (
              <div
                key={i}
                onClick={() => setSelectedElement(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  padding: '8px',
                  borderRadius: '4px',
                  background: CATEGORY_COLORS[el.category || 'default'] || CATEGORY_COLORS['default'],
                  cursor: 'pointer',
                  opacity: isVisible ? 1 : 0.2,
                  transition: 'opacity 0.2s',
                  display: 'flex',
                  flexDirection: 'column',
                  justifyContent: 'space-between',
                  height: '60px',
                  border: selectedElement === el ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '1px solid transparent',
                }}
              >
                <Text variant="caption">{el.atomicNumber}</Text>
                <Text weight="bold" align="center">{el.symbol}</Text>
              </div>
            );
          })}
        </Box>

        {selectedElement && (
          <Card padding={20} shadow="md">
            <Stack gap={8}>
              <Heading level={3}>{selectedElement.name}</Heading>
              <Text>Symbol: {selectedElement.symbol}</Text>
              <Text>Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text>Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text>Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}

        <Divider />

        <Stack direction="horizontal" gap={16} wrap>
          {categories.map((cat) => (
            <Stack key={cat} direction="horizontal" gap={8} align="center">
              <Box style={{ width: 16, height: 16, background: CATEGORY_COLORS[cat] || CATEGORY_COLORS['default'], borderRadius: 4 }} />
              <Text variant="bodySmall">{cat}</Text>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Box, 
  Text, 
  Heading, 
  Button, 
  Badge, 
  Tabs, 
  Table, 
  Icon, 
  Spinner 
} from '@ggui-ai/design/primitives';

interface Product {
  id?: string;
  name?: string;
  price?: number;
  currency?: string;
  rating?: number;
  reviewCount?: number;
  stock?: number;
  description?: string;
  specifications?: any[];
  reviews?: any[];
}

interface Props {
  product: Product;
  onAddToCart?: (payload: { productId: string; quantity: number }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { 
    product = {} 
  } = props;

  const {
    id = 'unknown',
    name = 'Product Name',
    price = 0,
    currency = 'USD',
    rating = 0,
    reviewCount = 0,
    stock = 0,
    description = 'No description available.',
    specifications = [],
    reviews = []
  } = product;

  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [status, setStatus] = useState<'idle' | 'success' | 'error'>('idle');

  const isOutOfStock = stock <= 0;
  const isLowStock = stock > 0 && stock <= 5;

  const handleAddToCart = async () => {
    setIsSubmitting(true);
    setStatus('idle');
    try {
      if (props.onAddToCart) {
        props.onAddToCart({ productId: id, quantity });
      }
      setStatus('success');
      setTimeout(() => setStatus('idle'), 3000);
    } catch {
      setStatus('error');
    } finally {
      setIsSubmitting(false);
    }
  };

  const renderStars = (rating: number) => (
    <Stack direction="horizontal" gap={2} align="center">
      {[1, 2, 3, 4, 5].map((val) => (
        <Icon 
          key={val} 
          name={val <= Math.floor(rating) ? 'check' : 'minus'} 
          size={16} 
          color={val <= Math.floor(rating) ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-neutral-300, #d1d5db)'} 
        />
      ))}
      <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">({reviewCount})</Text>
    </Stack>
  );

  return (
    <Container maxWidth="lg" padding={24}>
      <Stack gap={24}>
        <Stack direction="horizontal" gap={32} wrap>
          <Box 
            background="var(--ggui-color-neutral-200, #e5e7eb)" 
            borderRadius={12} 
            padding={64} 
            style={{ flex: 1, minWidth: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Heading level={3}>{name}</Heading>
          </Box>

          <Stack gap={16} style={{ flex: 1, minWidth: '300px' }}>
            <Heading level={1}>{name}</Heading>
            <Text variant="bodyLarge" weight="bold">{currency} {price.toFixed(2)}</Text>
            {renderStars(rating)}
            <Box>
              {isOutOfStock ? (
                <Badge variant="error">Out of Stock</Badge>
              ) : isLowStock ? (
                <Badge variant="warning">Low Stock</Badge>
              ) : (
                <Badge variant="success">In Stock</Badge>
              )}
            </Box>
          </Stack>
        </Stack>

        <Card padding={24}>
          <Tabs 
            activeKey={activeTab} 
            onChange={setActiveTab}
            items={[
              { 
                key: 'description', 
                label: 'Description', 
                content: <Text variant="body">{description}</Text> 
              },
              { 
                key: 'specifications', 
                label: 'Specifications', 
                content: (
                  <Table 
                    columns={[
                      { key: 'key', header: 'Specification' },
                      { key: 'value', header: 'Details' }
                    ]}
                    data={specifications}
                  />
                ) 
              },
              { 
                key: 'reviews', 
                label: 'Reviews', 
                content: (
                  <Stack gap={16}>
                    {reviews.map((r: any, i: number) => (
                      <Box key={i} padding={16} background="var(--ggui-color-neutral-100, #f3f4f6)" borderRadius={8}>
                        <Stack gap={8}>
                          <Text weight="semibold">{r.author} - {r.rating} stars</Text>
                          <Text variant="bodySmall">{r.text}</Text>
                          <Text variant="caption" color="var(--ggui-color-neutral-500, #6b7280)">{r.date}</Text>
                        </Stack>
                      </Box>
                    ))}
                  </Stack>
                ) 
              }
            ]} 
          />
        </Card>

        <Card padding={24}>
          <Stack direction="horizontal" gap={16} align="center">
            <Stack direction="horizontal" align="center" gap={8}>
              <Button size="sm" variant="outline" onClick={() => setQuantity(Math.max(1, quantity - 1))}>-</Button>
              <Text style={{ width: '40px', textAlign: 'center' }}>{quantity}</Text>
              <Button size="sm" variant="outline" onClick={() => setQuantity(Math.min(stock, quantity + 1))}>+</Button>
            </Stack>

            <Button 
              variant="primary" 
              onClick={handleAddToCart} 
              disabled={isOutOfStock || isSubmitting}
              loading={isSubmitting}
            >
              Add to Cart
            </Button>

            {status === 'success' && <Text color="var(--ggui-color-success-600, #16a34a)">Added successfully!</Text>}
            {status === 'error' && <Text color="var(--ggui-color-error-600, #dc2626)">Failed to add.</Text>}
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Card, Stack, Text, Heading, Button, Input, Box, Divider, Badge } from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback for sending messages */
  onSendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent(props: Props) {
  const { title, currentUser, participantCount, messages: initialMessages, onSendMessage } = props;
  const [messages, setMessages] = useState(initialMessages);
  const [inputText, setInputText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleAgentData = (event: any) => {
      if (event.detail) {
        setMessages((prev) => [...prev, event.detail]);
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    if (!inputText.trim()) return;
    const payload = {
      text: inputText,
      timestamp: new Date().toISOString(),
    };
    onSendMessage(payload);
    setInputText('');
  };

  return (
    <Card padding={0} border={true} radius="lg" style={{ height: '500px', display: 'flex', flexDirection: 'column' }}>
      <Box paddingX={16} paddingY={12} style={{ borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={4}>{title}</Heading>
          {participantCount !== undefined && <Badge variant="secondary">{participantCount} participants</Badge>}
        </Stack>
      </Box>

      <Box 
        padding={16} 
        style={{ flex: 1, overflowY: 'auto', background: 'var(--ggui-color-surface, #fafafa)' }}
      >
        <div ref={scrollRef}>
          <Stack gap={12}>
            {messages.map((msg, idx) => {
              const isOwn = msg.sender === currentUser;
              return (
                <Stack key={idx} align={isOwn ? 'end' : 'start'}>
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {msg.sender ?? 'Unknown'} • {new Date(msg.timestamp ?? '').toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </Text>
                  <Box 
                    paddingX={12} 
                    paddingY={8} 
                    borderRadius={8}
                    background={isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)'}
                  >
                    <Text color={isOwn ? '#ffffff' : 'var(--ggui-color-onSurface, #18181b)'}>
                      {msg.text}
                    </Text>
                  </Box>
                </Stack>
              );
            })}
          </Stack>
        </div>
      </Box>

      <Box padding={16} style={{ borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Stack direction="horizontal" gap={8} align="end">
          <div style={{ flex: 1 }}>
            <Input 
              label="Message"
              value={inputText} 
              onChange={setInputText} 
              placeholder="Type a message..." 
              onKeyDown={(e: any) => e.key === 'Enter' && handleSend()}
            />
          </div>
          <Button variant="primary" onClick={handleSend} disabled={!inputText.trim()}>
            Send Message
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import { Card, Stack, Text, Heading, Container, Box, Divider } from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  stocks?: Stock[];
  lastUpdated?: string;
}

/**
 * StockTickerDashboard
 * A responsive dashboard displaying real-time stock information.
 */
export default function StockTickerDashboard({
  stocks = [],
  lastUpdated = new Date().toISOString(),
}: Props) {
  const [liveStocks, setLiveStocks] = useState<Stock[]>(stocks);
  const [updatedTime, setUpdatedTime] = useState<string>(lastUpdated);

  // Stream Contract: Listen for real-time updates via ggui:agent-data
  useEffect(() => {
    const handleData = (event: any) => {
      // Data format: { detail: { stocks: [...], lastUpdated: '...' } }
      const data = event.detail;
      if (data) {
        if (Array.isArray(data.stocks)) {
          setLiveStocks(data.stocks);
        }
        if (data.lastUpdated) {
          setUpdatedTime(data.lastUpdated);
        }
      }
    };

    window.addEventListener('ggui:agent-data', handleData);
    return () => window.removeEventListener('ggui:agent-data', handleData);
  }, []);

  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={24}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="center">
          <Heading level={1}>Market Watch</Heading>
          <Text variant="caption" color="var(--ggui-color-neutral-500)">
            Last updated: {new Date(updatedTime).toLocaleTimeString()}
          </Text>
        </Stack>

        <Divider />

        {/* Stock Grid */}
        {liveStocks.length > 0 ? (
          <CardGrid columns={{ sm: 1, md: 3 }} gap={16}>
            {liveStocks.map((stock, index) => {
              const change = stock.change ?? 0;
              const isPositive = change >= 0;
              const color = isPositive 
                ? 'var(--ggui-color-success-600)' 
                : 'var(--ggui-color-error-600)';

              return (
                <Card 
                  key={stock.symbol ?? index} 
                  padding={16} 
                  shadow="sm"
                  style={{ 
                    border: `1px solid ${color}`,
                    backgroundColor: 'var(--ggui-color-surface)'
                  }}
                >
                  <Stack gap={8}>
                    <Stack direction="horizontal" justify="between" align="start">
                      <Text variant="label" weight="bold" size="lg">{stock.symbol ?? 'N/A'}</Text>
                      <Text variant="bodySmall" color="var(--ggui-color-neutral-500)">{stock.name}</Text>
                    </Stack>

                    <Heading level={2}>${stock.price?.toFixed(2) ?? '0.00'}</Heading>

                    <Stack direction="horizontal" gap={4} align="center">
                      <Text style={{ color, fontWeight: 'var(--ggui-font-weight-bold)' }}>
                        {isPositive ? '▲' : '▼'} {Math.abs(change).toFixed(2)}
                      </Text>
                      <Text style={{ color }}>
                        ({Math.abs(stock.changePercent ?? 0).toFixed(2)}%)
                      </Text>
                    </Stack>
                  </Stack>
                </Card>
              );
            })}
          </CardGrid>
        ) : (
          <Box padding={40} style={{ textAlign: 'center' }}>
            <Text>No stock data available.</Text>
          </Box>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { Container, Card, Stack, Text, Heading, Divider, Box, Spacer } from '@ggui-ai/design/primitives';
import { Input, Select, Checkbox, Toggle, Button, RadioGroup } from '@ggui-ai/design/components';

interface Props {
  initialProfile?: { 
    name?: string; 
    email?: string; 
    avatar?: string; 
    role?: string; 
    emailNotifications?: boolean; 
    theme?: string 
  };
  avatarOptions: string[];
  roleOptions: string[];
  onComplete?: (data: any) => void;
}

export default function GeneratedComponent(props: Props) {
  const { initialProfile = {}, avatarOptions, roleOptions, onComplete } = props;
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? avatarOptions[0],
    role: initialProfile.role ?? roleOptions[0],
    emailNotifications: initialProfile.emailNotifications ?? false,
    theme: initialProfile.theme ?? 'light'
  });

  const isEmailValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email);
  const isStep1Valid = formData.name.trim() !== '' && isEmailValid;

  const next = () => setStep((s) => Math.min(s + 1, 3));
  const back = () => setStep((s) => Math.max(s - 1, 1));

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap={16}>
            <Heading level={3}>Step 1: Profile Setup</Heading>
            <Input 
              label="Name" 
              value={formData.name} 
              onChange={(val) => setFormData({...formData, name: val})} 
              required 
            />
            <Input 
              label="Email" 
              type="email" 
              value={formData.email} 
              onChange={(val) => setFormData({...formData, email: val})} 
              required 
              error={!isEmailValid && formData.email !== '' ? 'Invalid email format' : undefined}
            />
            <Text variant="label">Select Avatar</Text>
            <RadioGroup
              direction="horizontal"
              value={formData.avatar}
              onChange={(val) => setFormData({...formData, avatar: val})}
              options={avatarOptions.map(opt => ({ value: opt, label: opt }))}
            />
          </Stack>
        );
      case 2:
        return (
          <Stack gap={16}>
            <Heading level={3}>Step 2: Preferences</Heading>
            <Select
              label="Role"
              value={formData.role}
              onChange={(val) => setFormData({...formData, role: val})}
              options={roleOptions.map(r => ({ value: r, label: r }))}
            />
            <Checkbox 
              label="Enable email notifications" 
              checked={formData.emailNotifications} 
              onChange={(val) => setFormData({...formData, emailNotifications: val})} 
            />
            <Toggle 
              label={`Theme: ${formData.theme === 'dark' ? 'Dark' : 'Light'}`} 
              checked={formData.theme === 'dark'} 
              onChange={(val) => setFormData({...formData, theme: val ? 'dark' : 'light'})} 
            />
          </Stack>
        );
      case 3:
        return (
          <Stack gap={16}>
            <Heading level={3}>Step 3: Review & Confirm</Heading>
            <Card padding={16} border>
              <Stack gap={8}>
                <Text><strong>Name:</strong> {formData.name}</Text>
                <Text><strong>Email:</strong> {formData.email}</Text>
                <Text><strong>Avatar:</strong> {formData.avatar}</Text>
                <Text><strong>Role:</strong> {formData.role}</Text>
                <Text><strong>Notifications:</strong> {formData.emailNotifications ? 'Yes' : 'No'}</Text>
                <Text><strong>Theme:</strong> {formData.theme}</Text>
              </Stack>
            </Card>
          </Stack>
        );
      default: return null;
    }
  };

  return (
    <Container maxWidth="sm" padding={24}>
      <Card padding={24}>
        <Stack gap={24}>
          <Box>
            <Text variant="caption" color="var(--ggui-color-neutral-500)">Step {step} of 3</Text>
            <Box background="var(--ggui-color-neutral-200)" borderRadius={4} height={4} margin="4px 0">
              <Box background="var(--ggui-color-primary-600)" borderRadius={4} height={4} style={{ width: `${(step / 3) * 100}%`, transition: 'width 0.3s ease' }} />
            </Box>
          </Box>

          {renderStep()}

          <Divider />

          <Stack direction="horizontal" justify="between">
            <Button variant="secondary" onClick={back} disabled={step === 1}>Back</Button>
            {step < 3 ? (
              <Button onClick={next} disabled={step === 1 && !isStep1Valid}>Next</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete?.(formData)}>Complete Setup</Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

