import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Progress,
  Input,
  RadioGroup,
  Checkbox,
  TextArea,
  Button,
  Box,
  Divider,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions?: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels?: string[];
  /** Callback for submission */
  onSubmit?: (data: {
    name: string;
    email: string;
    satisfaction: number;
    features: string[];
    comments: string;
  }) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    featureOptions = [
      "Dashboard Analytics",
      "Team Collaboration",
      "API Integration",
      "Custom Workflows",
      "Mobile App",
      "AI Assistance"
    ],
    satisfactionLabels = [
      "Very Unsatisfied",
      "Unsatisfied",
      "Neutral",
      "Satisfied",
      "Very Satisfied"
    ],
    onSubmit
  } = props;

  const [currentStep, setCurrentStep] = useState(0); // 0 to 4
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 0,
    features: [] as string[],
    comments: ''
  });

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  const isEmailValid = useMemo(() => emailRegex.test(formData.email), [formData.email]);

  const canGoNext = useMemo(() => {
    if (currentStep === 0) return formData.name.trim().length > 0 && isEmailValid;
    if (currentStep === 1) return formData.satisfaction > 0;
    return true;
  }, [currentStep, formData, isEmailValid]);

  const handleNext = () => {
    if (currentStep < 4) setCurrentStep(prev => prev + 1);
  };

  const handleBack = () => {
    if (currentStep > 0) setCurrentStep(prev => prev - 1);
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      if (onSubmit) {
        await onSubmit(formData);
      }
    } catch (error) {
      console.error("Submission failed", error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const toggleFeature = (feature: string, checked: boolean) => {
    setFormData(prev => ({
      ...prev,
      features: checked
        ? [...prev.features, feature]
        : prev.features.filter(f => f !== feature)
    }));
  };

  const satisfactionOptions = useMemo(() => {
    return satisfactionLabels.map((label, index) => ({
      label,
      value: (index + 1).toString()
    }));
  }, [satisfactionLabels]);

  const renderStep = () => {
    switch (currentStep) {
      case 0:
        return (
          <Stack gap={24}>
            <Heading level={3}>Step 1: Contact Information</Heading>
            <Input
              label="Full Name"
              required
              placeholder="Enter your name"
              value={formData.name}
              onChange={(val) => setFormData(prev => ({ ...prev, name: val }))}
              helperText="Required for submission"
            />
            <Input
              label="Email Address"
              type="email"
              required
              placeholder="name@example.com"
              value={formData.email}
              onChange={(val) => setFormData(prev => ({ ...prev, email: val }))}
              error={formData.email && !isEmailValid ? "Please enter a valid email format" : undefined}
            />
          </Stack>
        );
      case 1:
        return (
          <Stack gap={24}>
            <Heading level={3}>Step 2: Satisfaction</Heading>
            <RadioGroup
              label="Overall, how satisfied are you?"
              value={formData.satisfaction.toString()}
              onChange={(val) => setFormData(prev => ({ ...prev, satisfaction: parseInt(val, 10) }))}
              options={satisfactionOptions}
            />
          </Stack>
        );
      case 2:
        return (
          <Stack gap={24}>
            <Heading level={3}>Step 3: Feature Interests</Heading>
            <Text variant="body">Select the features you are most interested in:</Text>
            <Stack gap={12}>
              {featureOptions.map((opt) => (
                <Checkbox
                  key={opt}
                  label={opt}
                  checked={formData.features.includes(opt)}
                  onChange={(checked) => toggleFeature(opt, checked)}
                />
              ))}
            </Stack>
          </Stack>
        );
      case 3:
        return (
          <Stack gap={24}>
            <Heading level={3}>Step 4: Additional Feedback</Heading>
            <TextArea
              label="Comments (Optional)"
              placeholder="Share your thoughts with us..."
              value={formData.comments}
              onChange={(val) => setFormData(prev => ({ ...prev, comments: val }))}
              maxLength={500}
              showCount
              rows={5}
            />
          </Stack>
        );
      case 4:
        return (
          <Stack gap={24}>
            <Heading level={3}>Review & Submit</Heading>
            <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={16} borderRadius={8}>
              <Stack gap={16}>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
                  <Text variant="body">{formData.name || "—"}</Text>
                </Box>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
                  <Text variant="body">{formData.email || "—"}</Text>
                </Box>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Satisfaction</Text>
                  <Text variant="body">
                    {formData.satisfaction ? satisfactionLabels[formData.satisfaction - 1] : "Not rated"}
                  </Text>
                </Box>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Features</Text>
                  <Text variant="body">
                    {formData.features.length > 0 ? formData.features.join(", ") : "None selected"}
                  </Text>
                </Box>
                <Box>
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Comments</Text>
                  <Text variant="body">{formData.comments || "No comments"}</Text>
                </Box>
              </Stack>
            </Box>
          </Stack>
        );
      default:
        return null;
    }
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8)">
      <Card shadow="md" padding={32} radius="xl">
        <Stack gap={32}>
          {/* Progress Section */}
          <Stack gap={12}>
            <Stack direction="horizontal" justify="between" align="center">
              <Heading level={4} color="var(--ggui-color-primary-600)">Survey Progress</Heading>
              <Text variant="label" color="var(--ggui-color-neutral-500)">
                {currentStep < 4 ? `Step ${currentStep + 1} of 4` : "Final Review"}
              </Text>
            </Stack>
            <Progress
              value={currentStep === 4 ? 100 : (currentStep / 4) * 100}
              variant="default"
              size="sm"
            />
          </Stack>

          {/* Body Section */}
          <Box style={{ minHeight: '360px' }}>
            {renderStep()}
          </Box>

          <Divider margin={8} />

          {/* Navigation Section */}
          <Stack direction="horizontal" gap={12} justify="between">
            <Button
              variant="ghost"
              onPress={handleBack}
              disabled={currentStep === 0 || isSubmitting}
            >
              Back
            </Button>

            <Spacer size="flex" />

            {currentStep < 4 ? (
              <Button
                variant="primary"
                onPress={handleNext}
                disabled={!canGoNext}
              >
                Next
              </Button>
            ) : (
              <Button
                variant="primary"
                loading={isSubmitting}
                onPress={handleSubmit}
              >
                Submit Survey
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Card,
  Stack,
  Text,
  Button,
  Input,
  Select,
  Avatar,
  Badge,
  Box,
  Divider,
  Container,
  Spacer,
  Icon
} from '@ggui-ai/design/primitives';

interface Task {
  id: string;
  title: string;
  priority: 'low' | 'medium' | 'high';
  assignee: string;
  column: string;
  dueDate?: string;
}

interface Column {
  id: string;
  name: string;
}

interface Props {
  /** Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate */
  tasks?: Array<{
    id?: string;
    title?: string;
    priority?: 'low' | 'medium' | 'high';
    assignee?: string;
    column?: string;
    dueDate?: string;
  }>;
  /** Column definitions */
  columns?: Array<{ id?: string; name?: string }>;
  /** Callback for task updates */
  onTaskUpdate?: (payload: { action: string; taskId?: string; data: any }) => void;
}

export default function GeneratedComponent({
  tasks: initialTasks = [],
  columns = [
    { id: 'todo', name: 'To Do' },
    { id: 'in-progress', name: 'In Progress' },
    { id: 'done', name: 'Done' }
  ],
  onTaskUpdate
}: Props) {
  const [localTasks, setLocalTasks] = useState<Task[]>(
    initialTasks.map((t) => ({
      id: t.id ?? Math.random().toString(36).substr(2, 9),
      title: t.title ?? 'Untitled Task',
      priority: t.priority ?? 'medium',
      assignee: t.assignee ?? '??',
      column: t.column ?? 'todo',
      dueDate: t.dueDate
    }))
  );

  const [addingToColumn, setAddingToColumn] = useState<string | null>(null);
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [formState, setFormState] = useState({ title: '', priority: 'medium' as 'low' | 'medium' | 'high' });

  const summary = useMemo(() => {
    const total = localTasks.length;
    const completed = localTasks.filter((t) => t.column === 'done').length;
    return { total, completed };
  }, [localTasks]);

  const handleMove = (taskId: string, newColumn: string) => {
    const updated = localTasks.map((t) => (t.id === taskId ? { ...t, column: newColumn } : t));
    setLocalTasks(updated);
    onTaskUpdate?.({ action: 'move', taskId, data: { column: newColumn } });
  };

  const handleSaveEdit = (taskId: string) => {
    const updated = localTasks.map((t) => (t.id === taskId ? { ...t, title: formState.title } : t));
    setLocalTasks(updated);
    setEditingTaskId(null);
    onTaskUpdate?.({ action: 'edit', taskId, data: { title: formState.title } });
  };

  const handleAddTask = (columnId: string) => {
    if (!formState.title.trim()) return;
    const newTask: Task = {
      id: Math.random().toString(36).substr(2, 9),
      title: formState.title,
      priority: formState.priority,
      assignee: 'ME',
      column: columnId
    };
    setLocalTasks([...localTasks, newTask]);
    setAddingToColumn(null);
    setFormState({ title: '', priority: 'medium' });
    onTaskUpdate?.({ action: 'create', taskId: newTask.id, data: newTask });
  };

  const getPriorityVariant = (p: string) => {
    if (p === 'high') return 'error';
    if (p === 'medium') return 'warning';
    return 'info';
  };

  return (
    <Container maxWidth="full" padding={24}>
      <Stack gap={24}>
        {/* Summary Bar */}
        <Card padding="12px 20px" shadow="sm" radius="md">
          <Stack direction="horizontal" justify="between" align="center">
            <Stack direction="horizontal" gap={16} align="center">
              <Icon name="menu" size={20} color="var(--ggui-color-primary-600)" />
              <Heading level={4}>Task Board</Heading>
            </Stack>
            <Stack direction="horizontal" gap={24} align="center">
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Total Tasks</Text>
                <Text weight="bold" size="xl">{summary.total}</Text>
              </Box>
              <Divider orientation="vertical" margin={8} />
              <Box>
                <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Completed</Text>
                <Text weight="bold" size="xl" color="var(--ggui-color-success-600)">{summary.completed}</Text>
              </Box>
            </Stack>
          </Stack>
        </Card>

        {/* Board Columns */}
        <Box style={{ display: 'grid', gridTemplateColumns: `repeat(${columns.length}, 1fr)`, gap: '24px', alignItems: 'start' }}>
          {columns.map((col) => {
            const colId = col.id ?? 'unknown';
            const colTasks = localTasks.filter((t) => t.column === colId);

            return (
              <Box 
                key={colId} 
                padding={16} 
                borderRadius="var(--ggui-shape-radius-xl)"
                background="var(--ggui-color-surfaceVariant)"
                style={{ minHeight: '500px' }}
              >
                <Stack gap={16}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text weight="semibold" variant="body">{col.name ?? 'Column'}</Text>
                    <Badge variant="secondary" pill>{colTasks.length}</Badge>
                  </Stack>

                  <Stack gap={12}>
                    {colTasks.map((task) => (
                      <Card key={task.id} padding={12} shadow="sm" radius="md" border>
                        <Stack gap={8}>
                          <Stack direction="horizontal" justify="between" align="start">
                            <Badge variant={getPriorityVariant(task.priority)} size="sm">
                              {task.priority.toUpperCase()}
                            </Badge>
                            <Button 
                              variant="ghost" 
                              size="xs" 
                              onClick={() => {
                                setEditingTaskId(task.id);
                                setFormState({ ...formState, title: task.title });
                              }}
                            >
                              Edit
                            </Button>
                          </Stack>

                          {editingTaskId === task.id ? (
                            <Stack gap={8}>
                              <Input 
                                label="Task Title"
                                value={formState.title} 
                                onChange={(val) => setFormState({ ...formState, title: val })} 
                                autoFocus 
                              />
                              <Stack direction="horizontal" gap={4}>
                                <Button size="xs" onClick={() => handleSaveEdit(task.id)}>Save</Button>
                                <Button size="xs" variant="ghost" onClick={() => setEditingTaskId(null)}>Cancel</Button>
                              </Stack>
                            </Stack>
                          ) : (
                            <Text weight="medium">{task.title}</Text>
                          )}

                          <Stack direction="horizontal" justify="between" align="center">
                            <Stack direction="horizontal" gap={8} align="center">
                              <Avatar name={task.assignee} size="xs" />
                              {task.dueDate && (
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                                  {task.dueDate}
                                </Text>
                              )}
                            </Stack>

                            <Select
                              size="sm"
                              value={task.column}
                              onChange={(val) => handleMove(task.id, val)}
                              options={columns.map(c => ({ value: c.id ?? '', label: `Move to ${c.name}` }))}
                            />
                          </Stack>
                        </Stack>
                      </Card>
                    ))}
                  </Stack>

                  {addingToColumn === colId ? (
                    <Card padding={12} border radius="md">
                      <Stack gap={12}>
                        <Input 
                          label="New Task Title"
                          placeholder="What needs to be done?" 
                          value={formState.title} 
                          onChange={(val) => setFormState({ ...formState, title: val })}
                        />
                        <Select 
                          label="Priority"
                          value={formState.priority}
                          onChange={(val) => setFormState({ ...formState, priority: val as any })}
                          options={[
                            { value: 'low', label: 'Low' },
                            { value: 'medium', label: 'Medium' },
                            { value: 'high', label: 'High' }
                          ]}
                        />
                        <Stack direction="horizontal" gap={8}>
                          <Button fullWidth size="sm" onClick={() => handleAddTask(colId)}>Add</Button>
                          <Button fullWidth size="sm" variant="ghost" onClick={() => setAddingToColumn(null)}>Cancel</Button>
                        </Stack>
                      </Stack>
                    </Card>
                  ) : (
                    <Button 
                      variant="outline" 
                      fullWidth 
                      leftIcon={<Icon name="plus" size={16} />}
                      onClick={() => {
                        setAddingToColumn(colId);
                        setFormState({ title: '', priority: 'medium' });
                      }}
                    >
                      Add Task
                    </Button>
                  )}
                </Stack>
              </Box>
            );
          })}
        </Box>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import { 
  Container, 
  Stack, 
  Card, 
  Text, 
  Heading, 
  Box, 
  Divider, 
  Spacer 
} from '@ggui-ai/design/primitives';
import { SearchField } from '@ggui-ai/design/components';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

export default function GeneratedComponent({ elements = [] }: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<ElementData | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchQuery) return elements;
    const query = searchQuery.toLowerCase();
    return elements.filter(el => 
      el.name?.toLowerCase().includes(query) || 
      el.symbol?.toLowerCase().includes(query)
    );
  }, [elements, searchQuery]);

  const categories = [
    { label: 'Alkali Metal', category: 'alkali-metal', color: 'var(--ggui-color-error-100, #fee2e2)' },
    { label: 'Alkaline Earth', category: 'alkaline-earth-metal', color: 'var(--ggui-color-warning-100, #fef3c7)' },
    { label: 'Transition Metal', category: 'transition-metal', color: 'var(--ggui-color-neutral-100, #f3f4f6)' },
    { label: 'Post-Transition', category: 'post-transition-metal', color: 'var(--ggui-color-success-100, #dcfce7)' },
    { label: 'Metalloid', category: 'metalloid', color: 'var(--ggui-color-info-100, #cffafe)' },
    { label: 'Nonmetal', category: 'nonmetal', color: 'var(--ggui-color-primary-100, #e0f2fe)' },
    { label: 'Halogen', category: 'halogen', color: 'var(--ggui-color-primary-200, #bae6fd)' },
    { label: 'Noble Gas', category: 'noble-gas', color: 'var(--ggui-color-primary-300, #7dd3fc)' },
    { label: 'Lanthanide', category: 'lanthanide', color: 'var(--ggui-color-success-50, #f0fdf4)' },
    { label: 'Actinide', category: 'actinide', color: 'var(--ggui-color-error-50, #fef2f2)' },
  ];

  const getCategoryColor = (category?: string) => {
    const found = categories.find(c => c.category === category);
    return found?.color ?? 'var(--ggui-color-neutral-50, #f9fafb)';
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="end" wrap>
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={1}>Periodic Table</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Interactive chemical element explorer
            </Text>
          </Stack>
          <Box paddingY="var(--ggui-spacing-2, 8px)">
            <SearchField
              value={searchQuery}
              onChange={setSearchQuery}
              placeholder="Search by name or symbol..."
              size="md"
            />
          </Box>
        </Stack>

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4, 16px)" border radius="md" shadow="none">
          <Stack direction="horizontal" gap="var(--ggui-spacing-4, 16px)" wrap align="center" justify="center">
            {categories.map((cat) => (
              <Stack key={cat.category} direction="horizontal" gap="var(--ggui-spacing-2, 8px)" align="center">
                <Box 
                  padding="var(--ggui-spacing-2, 8px)" 
                  borderRadius="var(--ggui-shape-radius-sm, 4px)" 
                  background={cat.color}
                  style={{ width: 'var(--ggui-spacing-4, 16px)', height: 'var(--ggui-spacing-4, 16px)', border: '1px solid var(--ggui-color-outline, #d4d4d8)' }}
                />
                <Text variant="caption" weight="medium">{cat.label}</Text>
              </Stack>
            ))}
          </Stack>
        </Card>

        {/* Grid Container */}
        <Box 
          style={{ 
            display: 'grid', 
            gridTemplateColumns: 'repeat(18, 1fr)', 
            gap: 'var(--ggui-spacing-1, 4px)',
            overflowX: 'auto',
            paddingBottom: 'var(--ggui-spacing-4, 16px)'
          }}
        >
          {filteredElements.map((el) => (
            <div
              key={`${el.atomicNumber}-${el.symbol}`}
              onClick={() => setSelectedElement(el)}
              style={{
                gridRow: el.row ?? 'auto',
                gridColumn: el.col ?? 'auto',
                backgroundColor: getCategoryColor(el.category),
                borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                border: selectedElement?.atomicNumber === el.atomicNumber 
                  ? '2px solid var(--ggui-color-primary-600, #0284c7)' 
                  : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                padding: 'var(--ggui-spacing-1, 4px)',
                aspectRatio: '1/1',
                cursor: 'pointer',
                display: 'flex',
                flexDirection: 'column',
                justifyContent: 'space-between',
                transition: 'transform 0.1s ease-in-out',
                position: 'relative'
              }}
              role="button"
              tabIndex={0}
            >
              <Text 
                variant="caption" 
                size="xs" 
                weight="bold" 
                style={{ position: 'absolute', top: '2px', left: '4px' }}
              >
                {el.atomicNumber}
              </Text>
              <Spacer size="flex" />
              <Text 
                align="center" 
                weight="bold" 
                style={{ fontSize: 'var(--ggui-font-size-base, 16px)' }}
              >
                {el.symbol}
              </Text>
              <Text 
                variant="caption" 
                align="center" 
                truncate 
                style={{ fontSize: '10px' }}
              >
                {el.name}
