        </Box>

        {/* Detail Panel */}
        {selectedElement ? (
          <div style={{ animation: 'ggui-slideInUp 300ms ease-out' }}>
            <Card padding="var(--ggui-spacing-6, 24px)" radius="xl" border shadow="md">
              <Stack direction="horizontal" gap="var(--ggui-spacing-8, 32px)" align="start" wrap>
                <Box 
                  background={getCategoryColor(selectedElement.category)}
                  padding="var(--ggui-spacing-8, 32px)"
                  borderRadius="var(--ggui-shape-radius-lg, 12px)"
                  style={{ 
                    minWidth: '120px', 
                    display: 'flex', 
                    flexDirection: 'column', 
                    alignItems: 'center',
                    border: '1px solid var(--ggui-color-outline, #d4d4d8)'
                  }}
                >
                  <Text variant="bodyLarge" weight="bold">{selectedElement.atomicNumber}</Text>
                  <Heading level={1}>{selectedElement.symbol}</Heading>
                  <Text weight="medium">{selectedElement.name}</Text>
                </Box>

                <Stack gap="var(--ggui-spacing-4, 16px)" style={{ flex: 1, minWidth: '240px' }}>
                  <Heading level={3}>{selectedElement.name}</Heading>
                  <Divider margin="var(--ggui-spacing-2, 8px)" />

                  <Stack direction="horizontal" gap="var(--ggui-spacing-12, 48px)" wrap>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Number</Text>
                      <Text variant="bodyLarge" weight="semibold">{selectedElement.atomicNumber}</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Atomic Weight</Text>
                      <Text variant="bodyLarge" weight="semibold">{selectedElement.atomicWeight} u</Text>
                    </Stack>
                    <Stack gap="var(--ggui-spacing-1, 4px)">
                      <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Category</Text>
                      <Box 
                        paddingX="var(--ggui-spacing-2, 8px)" 
                        paddingY="var(--ggui-spacing-1, 4px)" 
