              </Stack>
            </Card>
          </div>
        ) : (
          <Card padding="var(--ggui-spacing-8, 32px)" border radius="lg" style={{ borderStyle: 'dashed', textAlign: 'center' }}>
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Select an element to view detailed properties.
            </Text>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import {
  Container,
  Stack,
  Box,
  Heading,
  Text,
  Badge,
  Button,
  Tabs,
  Table,
  Divider,
  Icon,
  Card,
  Spacer
} from '@ggui-ai/design/primitives';

interface Props {
  /** Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[] */
  product: {
    id?: string;
    name?: string;
    price?: number;
    currency?: string;
    rating?: number;
    reviewCount?: number;
    stock?: number;
    description?: string;
    specifications?: unknown[];
    reviews?: unknown[];
  };
  /** Called when user clicks Add to Cart. */
  onAddToCart?: (payload: { productId: string; quantity: number }) => void;
}

/**
 * Star Rating helper component using custom SVG mode for Icon
 */
function StarRating({ rating = 0 }: { rating: number }) {
  const stars = [1, 2, 3, 4, 5];
  return (
    <Stack direction="horizontal" gap={2}>
      {stars.map((star) => {
        const isFilled = star <= Math.round(rating);
        return (
          <Icon key={star} size={16} color={isFilled ? 'var(--ggui-color-warning-500, #f59e0b)' : 'var(--ggui-color-neutral-300, #d1d5db)'}>
            <svg viewBox="0 0 24 24" fill="currentColor">
              <path d="M12 17.27L18.18 21l-1.64-7.03L22 9.24l-7.19-.61L12 2 9.19 8.63 2 9.24l5.46 4.73L5.82 21z" />
            </svg>
          </Icon>
        );
      })}
    </Stack>
  );
}

export default function GeneratedComponent({
  product = {
    id: 'prod-001',
    name: 'Wireless Noise-Cancelling Headphones',
    price: 249.99,
    currency: 'USD',
    rating: 4.3,
    reviewCount: 128,
    stock: 12,
    description: 'Premium wireless headphones with adaptive noise cancellation, 30-hour battery life, and ultra-comfortable memory foam ear cushions.',
    specifications: [
      { key: 'Brand', value: 'AudioMax' },
      { key: 'Battery Life', value: '30 hours' }
    ],
    reviews: [
      { author: 'Alex M.', rating: 5, text: 'Best headphones I have ever owned. The noise cancellation is incredible.', date: '2026-03-01' }
    ]
  },
  onAddToCart
}: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const stock = product.stock ?? 0;
  const isOutOfStock = stock === 0;

  const handleIncrement = () => {
    if (quantity < stock) setQuantity((q) => q + 1);
  };

  const handleDecrement = () => {
    if (quantity > 1) setQuantity((q) => q - 1);
  };

  const handleAddToCart = () => {
    if (onAddToCart && product.id) {
      onAddToCart({ productId: product.id, quantity });
    }
  };

  // Specification Table Config
  const specColumns = [
    { key: 'key', header: 'Feature', width: '30%', weight: 'semibold' as const },
    { key: 'value', header: 'Detail' },
  ];

  const tabItems = [
    {
      key: 'description',
      label: 'Description',
      content: (
        <Box paddingY={16}>
          <Text variant="body" color="var(--ggui-color-neutral-700)">
            {product.description ?? 'No description available.'}
          </Text>
        </Box>
      ),
    },
    {
      key: 'specifications',
      label: 'Specifications',
      content: (
        <Box paddingY={16}>
          <Table
            columns={specColumns}
            data={(product.specifications as any[]) ?? []}
            bordered
            compact
          />
        </Box>
      ),
    },
    {
      key: 'reviews',
      label: 'Reviews',
      content: (
        <Stack gap={16} style={{ padding: '16px 0' }}>
          {((product.reviews as any[]) ?? []).length > 0 ? (
            (product.reviews as any[]).map((review, idx) => (
              <Card key={idx} padding={16} border radius="md" shadow="none">
                <Stack gap={8}>
                  <Stack direction="horizontal" justify="between" align="center">
                    <Text variant="label">{review.author}</Text>
                    <Text variant="caption" color="var(--ggui-color-neutral-500)">{review.date}</Text>
                  </Stack>
                  <StarRating rating={review.rating} />
                  <Text variant="bodySmall" color="var(--ggui-color-neutral-700)">{review.text}</Text>
                </Stack>
              </Card>
            ))
          ) : (
            <Text variant="bodySmall" align="center" color="var(--ggui-color-neutral-500)">
              No reviews yet.
            </Text>
          )}
        </Stack>
      ),
    },
  ];

  return (
    <Container maxWidth="xl" padding={24}>
      <Card padding={32} shadow="md" radius="xl">
        <Stack direction="horizontal" gap={48} align="start" wrap>
          {/* Product Image Section */}
          <Box
            background="linear-gradient(135deg, var(--ggui-color-neutral-100, #f3f4f6), var(--ggui-color-neutral-200, #e5e7eb))"
            borderRadius={16}
            padding={64}
            style={{
              flex: '1 1 400px',
              minHeight: '400px',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center'
            }}
          >
            <Stack gap={16} align="center">
              <Icon name="settings" size={64} color="var(--ggui-color-neutral-400)" />
              <Heading level={3} color="var(--ggui-color-neutral-500)" align="center">
                {product.name}
              </Heading>
            </Stack>
          </Box>

          {/* Product Details Section */}
          <Stack gap={24} style={{ flex: '1 1 350px' }}>
            <Stack gap={12}>
              <Badge
                variant={isOutOfStock ? 'error' : stock < 5 ? 'warning' : 'success'}
                size="sm"
              >
                {isOutOfStock ? 'Out of Stock' : stock < 5 ? 'Low Stock' : 'In Stock'}
              </Badge>
              <Heading level={1}>{product.name ?? 'Untitled Product'}</Heading>
              <Stack direction="horizontal" gap={8} align="center">
                <StarRating rating={product.rating ?? 0} />
                <Text variant="caption" color="var(--ggui-color-neutral-500)">
                  ({product.reviewCount ?? 0} reviews)
                </Text>
              </Stack>
            </Stack>

            <Text size="3xl" weight="bold" color="var(--ggui-color-primary-600)">
              {product.currency ?? '$'} {product.price?.toFixed(2) ?? '0.00'}
            </Text>

            <Divider />

            <Tabs
              items={tabItems}
              activeKey={activeTab}
              onChange={setActiveTab}
              variant="line"
            />

            <Spacer size={16} />

            {/* Actions Section */}
            {!isOutOfStock && (
              <Stack gap={16}>
                <Stack gap={8}>
                  <Text variant="label">Quantity</Text>
                  <Stack direction="horizontal" gap={12} align="center">
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={handleDecrement}
                      disabled={quantity <= 1}
                    >
                      <Icon name="minus" size={16} />
                    </Button>
                    <Box style={{ minWidth: '40px', textAlign: 'center' }}>
                      <Text weight="semibold">{quantity}</Text>
                    </Box>
                    <Button
                      variant="outline"
                      size="sm"
                      onClick={handleIncrement}
                      disabled={quantity >= stock}
                    >
                      <Icon name="plus" size={16} />
                    </Button>
                    <Text variant="caption" color="var(--ggui-color-neutral-500)">
                      {stock} available
                    </Text>
                  </Stack>
                </Stack>

                <Button
                  variant="primary"
                  size="lg"
                  fullWidth
                  leftIcon={<Icon name="check" size={20} />}
                  onClick={handleAddToCart}
                >
                  Add to Cart
                </Button>
              </Stack>
            )}

            {isOutOfStock && (
              <Button variant="secondary" size="lg" fullWidth disabled>
                Out of Stock
              </Button>
            )}
          </Stack>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Box,
  Card,
  Stack,
  Text,
  Heading,
  Button,
  Input,
  Badge,
} from '@ggui-ai/design/primitives';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name (for right-aligning own messages) */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages with sender name, text, and ISO timestamp */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback fired when user sends a message */
  sendMessage?: (payload: { text: string; timestamp: string }) => void;
}

export default function GeneratedComponent({
  title = "Team Chat",
  currentUser = "You",
  participantCount,
  messages = [],
  sendMessage,
}: Props) {
  const [inputValue, setInputValue] = useState("");
  const scrollRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom functionality
  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  };

  // Scroll to bottom on mount and whenever messages update
  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  // Stream Contract: Listen for incoming data from the agent
  useEffect(() => {
    const handleAgentData = (event: any) => {
      // Logic for handling streamed updates if required by the application flow
      console.log('ggui:agent-data received', event.detail);
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const handleSend = () => {
    const trimmedText = inputValue.trim();
    if (!trimmedText) return;

    const payload = {
      text: trimmedText,
      timestamp: new Date().toISOString(),
    };

    // Action Contract: Wire sendMessage callback
    if (sendMessage) {
      sendMessage(payload);
    }

    setInputValue("");
  };

  const formatTime = (isoString?: string) => {
    if (!isoString) return "";
    try {
      return new Date(isoString).toLocaleTimeString([], { 
        hour: '2-digit', 
        minute: '2-digit' 
      });
    } catch {
      return "";
    }
  };

  return (
    <Card 
      padding={0} 
      shadow="lg" 
      radius="xl"
      style={{ 
        height: '600px', 
        maxHeight: '90vh',
        display: 'flex', 
        flexDirection: 'column',
        overflow: 'hidden',
        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
        background: 'var(--ggui-color-surface, #fafafa)'
      }}
    >
      {/* Header Section */}
      <Box 
        paddingX={20}
        paddingY={16}
        style={{ 
          borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          background: 'var(--ggui-color-surface, #fafafa)' 
        }}
      >
        <Stack direction="horizontal" align="center" justify="between">
          <Stack direction="horizontal" gap={12} align="center">
            <Heading level={4}>{title ?? "Chat"}</Heading>
            {(participantCount ?? 0) > 0 && (
              <Badge variant="primary" size="sm">
                {participantCount} participants
              </Badge>
            )}
          </Stack>
        </Stack>
      </Box>

      {/* Message List Area */}
      <Box 
        ref={scrollRef}
        padding={20} 
        style={{ 
          flex: 1, 
          overflowY: 'auto',
          background: 'var(--ggui-color-surfaceVariant, #f4f4f5)'
        }}
      >
        <Stack gap={16}>
          {messages?.map((msg, index) => {
            const isMe = msg.sender === currentUser;
            const isFirstInGroup = index === 0 || messages[index - 1]?.sender !== msg.sender;

            return (
              <Stack 
                key={`${msg.timestamp}-${index}`} 
                align={isMe ? "end" : "start"} 
                gap={4}
              >
                {isFirstInGroup && (
                  <Text variant="label" size="xs" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {msg.sender ?? "Unknown"}
                  </Text>
                )}
                <Box
                  paddingX={16}
                  paddingY={10}
                  style={{
                    maxWidth: '80%',
                    backgroundColor: isMe 
                      ? 'var(--ggui-color-primary-600, #0284c7)' 
                      : 'var(--ggui-color-surface, #ffffff)',
                    color: isMe 
                      ? '#ffffff' 
                      : 'var(--ggui-color-onSurface, #18181b)',
                    borderRadius: isMe 
                      ? '16px 16px 4px 16px' 
                      : '16px 16px 16px 4px',
                    boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))',
                    border: isMe ? 'none' : '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  }}
                >
                  <Stack gap={4}>
                    <Text variant="body" color="inherit">
                      {msg.text ?? ""}
                    </Text>
                    <Text 
                      variant="caption" 
                      size="xs" 
                      align={isMe ? "right" : "left"}
                      color={isMe ? 'rgba(255,255,255,0.7)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                    >
                      {formatTime(msg.timestamp)}
                    </Text>
                  </Stack>
                </Box>
              </Stack>
            );
          })}
        </Stack>
      </Box>

      {/* Input Area */}
      <Box 
        padding={20} 
        style={{ 
          borderTop: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          background: 'var(--ggui-color-surface, #fafafa)'
        }}
      >
        <Stack direction="horizontal" gap={12} align="end">
          <div style={{ flex: 1 }}>
            {/* Added label prop for accessibility compliance */}
            <Input
              label="Compose Message"
              placeholder="Type your message..."
              value={inputValue}
              onChange={setInputValue}
              onKeyDown={(e: any) => {
                if (e.key === 'Enter') handleSend();
              }}
            />
          </div>
          <Button 
            variant="primary" 
            size="md"
            disabled={!inputValue.trim()}
            onClick={handleSend}
          >
            Send
          </Button>
        </Stack>
      </Box>
    </Card>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Text,
  Heading,
  Icon,
  Box,
} from '@ggui-ai/design/primitives';
import { CardGrid } from '@ggui-ai/design/compositions';

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<{
    symbol?: string;
    name?: string;
    price?: number;
    change?: number;
    changePercent?: number;
  }>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent(props: Props) {
  const [data, setData] = useState<Props>({
    stocks: props.stocks ?? [],
    lastUpdated: props.lastUpdated,
  });

  // Sync state with props
  useEffect(() => {
    setData({
      stocks: props.stocks ?? [],
      lastUpdated: props.lastUpdated,
    });
  }, [props.stocks, props.lastUpdated]);

  // Stream Contract: Listen for live updates from the agent
  useEffect(() => {
    const handleAgentData = (event: CustomEvent<Props>) => {
      if (event.detail) {
        setData((prev) => ({
          ...prev,
          ...event.detail,
        }));
      }
    };
    window.addEventListener('ggui:agent-data' as any, handleAgentData);
    return () => window.removeEventListener('ggui:agent-data' as any, handleAgentData);
  }, []);

  const { stocks, lastUpdated } = data;

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <Stack gap="var(--ggui-spacing-8, 32px)">
        {/* Dashboard Header */}
        <Stack
          direction="horizontal"
          justify="between"
          align="end"
          wrap
          gap="var(--ggui-spacing-4, 16px)"
        >
          <Stack gap="var(--ggui-spacing-1, 4px)">
            <Heading level={1} color="var(--ggui-color-onSurface, #18181b)">
              Market Watch
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Live portfolio tracking and performance
            </Text>
          </Stack>

          {lastUpdated && (
            <Box
              paddingX="var(--ggui-spacing-3, 12px)"
              paddingY="var(--ggui-spacing-1, 4px)"
              background="var(--ggui-color-surfaceVariant, #f4f4f5)"
              borderRadius="var(--ggui-shape-radius-full, 9999px)"
            >
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Updated: {new Date(lastUpdated).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
              </Text>
            </Box>
          )}
        </Stack>

        {/* Stock Cards Grid */}
        <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={24}>
          {stocks.map((stock, i) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const accentColor = isPositive
              ? 'var(--ggui-color-success-600, #16a34a)'
              : 'var(--ggui-color-error-600, #dc2626)';
            const lightAccent = isPositive
              ? 'var(--ggui-color-success-50, #f0fdf4)'
              : 'var(--ggui-color-error-50, #fef2f2)';

            return (
              <Card
                key={`${stock.symbol}-${i}`}
                padding={0}
                shadow="sm"
                radius="xl"
                border
              >
                <Stack gap={0}>
                  {/* Header Section */}
                  <Box
                    padding="var(--ggui-spacing-4, 16px)"
                    background={lightAccent}
                    style={{
                      borderBottom: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                    }}
                  >
                    <Stack direction="horizontal" justify="between" align="center">
                      <Stack gap={0}>
                        <Text
                          variant="label"
                          size="xl"
                          weight="bold"
                          color="var(--ggui-color-onSurface, #18181b)"
                        >
                          {stock.symbol ?? 'N/A'}
                        </Text>
                        <Text
                          variant="caption"
                          truncate
                          color="var(--ggui-color-onSurfaceVariant, #52525b)"
                          style={{ maxWidth: '140px' }}
                        >
                          {stock.name ?? 'Company Name'}
                        </Text>
                      </Stack>
                      <Box
                        padding={8}
                        borderRadius="var(--ggui-shape-radius-md, 8px)"
                        background="var(--ggui-color-surface, #ffffff)"
                      >
                        <Icon
                          name={isPositive ? 'chevron-up' : 'chevron-down'}
                          size={20}
                          color={accentColor}
                        />
                      </Box>
                    </Stack>
                  </Box>

                  {/* Pricing Section */}
                  <Box padding="var(--ggui-spacing-4, 16px)">
                    <Stack gap="var(--ggui-spacing-4, 16px)">
                      <Text
                        variant="body"
                        size="4xl"
                        weight="bold"
                        color="var(--ggui-color-onSurface, #18181b)"
                      >
                        ${(stock.price ?? 0).toLocaleString(undefined, {
                          minimumFractionDigits: 2,
                          maximumFractionDigits: 2,
                        })}
                      </Text>

                      <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-2, 8px)">
                        <Text
                          variant="label"
                          weight="semibold"
                          color={accentColor}
                          style={{
                            background: lightAccent,
                            padding: 'var(--ggui-spacing-1, 4px) var(--ggui-spacing-2, 8px)',
                            borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                          }}
                        >
                          {isPositive ? '+' : ''}
                          {(stock.change ?? 0).toFixed(2)}
                        </Text>
                        <Text variant="caption" weight="medium" color={accentColor}>
                          ({(stock.changePercent ?? 0).toFixed(2)}%)
                        </Text>
                      </Stack>
                    </Stack>
                  </Box>
                </Stack>
              </Card>
            );
          })}
        </CardGrid>

        {/* Empty State */}
        {stocks.length === 0 && (
          <Card padding={48} border radius="xl" shadow="none">
            <Stack align="center" gap="var(--ggui-spacing-4, 16px)">
              <Box
                background="var(--ggui-color-neutral-100, #f3f4f6)"
                padding={20}
                borderRadius="var(--ggui-shape-radius-full, 9999px)"
              >
                <Icon name="search" size={32} color="var(--ggui-color-neutral-400, #9ca3af)" />
              </Box>
              <Stack align="center" gap={4}>
                <Text weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
                  Waiting for market data...
                </Text>
                <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  Prices will appear here as the market moves.
                </Text>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Button,
  Input,
  Select,
  Toggle,
  Progress,
  Divider,
  Spacer,
  MotionKeyframes,
} from '@ggui-ai/design/primitives';

interface ProfileData {
  name: string;
  email: string;
  avatar: string;
  role: string;
  emailNotifications: boolean;
  theme: string;
}

interface Props {
  /** Pre-filled profile data for editing (all fields optional) */
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  /** Available avatar emojis to choose from */
  avatarOptions: string[];
  /** Available role options for the dropdown */
  roleOptions: string[];
  /** Callback fired when user completes onboarding */
  onComplete?: (data: ProfileData) => void;
}

export default function GeneratedComponent(props: Props) {
  const {
    initialProfile = {},
    avatarOptions = ["👤", "🧑‍💻", "🎨", "📊"],
    roleOptions = ["Developer", "Designer", "Manager", "Other"],
    onComplete,
  } = props;

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState<ProfileData>({
    name: initialProfile?.name ?? '',
    email: initialProfile?.email ?? '',
    avatar: initialProfile?.avatar ?? '',
    role: initialProfile?.role ?? '',
    emailNotifications: initialProfile?.emailNotifications ?? true,
    theme: initialProfile?.theme ?? 'light',
  });

  // Listener for external data updates
  useEffect(() => {
    const handleAgentData = (event: any) => {
      if (event.detail) {
        setFormData((prev) => ({ ...prev, ...event.detail }));
      }
    };
    window.addEventListener('ggui:agent-data', handleAgentData);
    return () => window.removeEventListener('ggui:agent-data', handleAgentData);
  }, []);

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isStep1Valid = formData.name.trim().length > 0 && isEmailValid(formData.email) && formData.avatar !== '';
  const isStep2Valid = formData.role !== '';

  const handleNext = () => setStep((s) => Math.min(s + 1, 3));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const handleSubmit = () => {
    onComplete?.(formData);
  };

  const progressValue = (step / 3) * 100;

  const selectRoleOptions = useMemo(() => 
    roleOptions.map(role => ({ value: role, label: role })), 
    [roleOptions]
  );

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <MotionKeyframes />
      <Stack gap={24}>
        {/* Header & Progress */}
        <Stack gap={12}>
          <Stack direction="horizontal" justify="between" align="end">
            <Heading level={2}>Onboarding</Heading>
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
              Step {step} of 3
            </Text>
          </Stack>
          <Progress value={progressValue} size="sm" variant="primary" />
        </Stack>

        <Card padding={32} shadow="md" radius="xl">
          <div style={{ animation: 'ggui-fadeIn 300ms ease-out' }} key={step}>
            {step === 1 && (
              <Stack gap={24}>
                <Heading level={4}>Profile Setup</Heading>
                <Input
                  label="Display Name"
                  placeholder="Enter your name"
                  value={formData.name}
                  onChange={(val) => setFormData({ ...formData, name: val })}
                  required
                />
                <Input
                  label="Email Address"
                  type="email"
                  placeholder="you@example.com"
                  value={formData.email}
                  onChange={(val) => setFormData({ ...formData, email: val })}
                  required
                  error={formData.email && !isEmailValid(formData.email) ? "Please enter a valid email" : undefined}
                />
                <Stack gap={8}>
                  <Text variant="label">Choose an Avatar</Text>
                  <Stack direction="horizontal" gap={12} wrap>
                    {avatarOptions.map((emoji) => (
                      <Button
                        key={emoji}
                        variant={formData.avatar === emoji ? 'primary' : 'outline'}
                        onClick={() => setFormData({ ...formData, avatar: emoji })}
                        style={{
                          fontSize: 'var(--ggui-font-size-2xl, 24px)',
                          width: '64px',
                          height: '64px',
                          padding: 0,
                        }}
                      >
                        {emoji}
                      </Button>
                    ))}
                  </Stack>
                </Stack>
              </Stack>
            )}

            {step === 2 && (
              <Stack gap={24}>
                <Heading level={4}>Preferences</Heading>
                <Select
                  label="What is your primary role?"
                  placeholder="Select a role"
                  value={formData.role}
                  onChange={(val) => setFormData({ ...formData, role: val })}
                  options={selectRoleOptions}
                  required
                />
                <Divider margin={8} />
                <Toggle
                  label="Enable Email Notifications"
                  checked={formData.emailNotifications}
                  onChange={(checked) => setFormData({ ...formData, emailNotifications: checked })}
                />
                <Toggle
                  label={`Theme Preference: ${formData.theme === 'dark' ? 'Dark' : 'Light'}`}
                  checked={formData.theme === 'dark'}
                  onChange={(checked) => setFormData({ ...formData, theme: checked ? 'dark' : 'light' })}
                />
              </Stack>
            )}

            {step === 3 && (
              <Stack gap={24}>
                <Heading level={4}>Review & Confirm</Heading>
                <Box padding={16} background="var(--ggui-color-surfaceVariant)" borderRadius="var(--ggui-shape-radius-lg)">
                  <Stack gap={16}>
                    <Stack direction="horizontal" align="center" gap={16}>
                      <Box 
                        background="var(--ggui-color-surface)" 
                        borderRadius="var(--ggui-shape-radius-full)"
                        style={{ width: 48, height: 48, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 24 }}
                      >
                        {formData.avatar}
                      </Box>
                      <Stack gap={2}>
                        <Text weight="semibold">{formData.name}</Text>
                        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{formData.email}</Text>
                      </Stack>
                    </Stack>

                    <Divider margin={4} color="var(--ggui-color-outlineVariant)" />

                    <Stack direction="horizontal" justify="between">
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Role</Text>
                      <Text variant="bodySmall" weight="medium">{formData.role}</Text>
                    </Stack>

                    <Stack direction="horizontal" justify="between">
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Notifications</Text>
                      <Text variant="bodySmall" weight="medium">{formData.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
                    </Stack>

                    <Stack direction="horizontal" justify="between">
                      <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">Theme</Text>
                      <Text variant="bodySmall" weight="medium" style={{ textTransform: 'capitalize' }}>{formData.theme}</Text>
                    </Stack>
                  </Stack>
                </Box>
                <Text variant="caption" align="center">
                  By clicking complete, you agree to our terms of service.
                </Text>
              </Stack>
            )}
          </div>
        </Card>

        {/* Footer Navigation */}
        <Stack direction="horizontal" justify="between">
          {step > 1 ? (
            <Button variant="outline" onClick={handleBack}>
              Go Back
            </Button>
          ) : (
            <Spacer size={1} />
          )}

          {step < 3 ? (
            <Button 
              variant="primary" 
              onClick={handleNext}
              disabled={(step === 1 && !isStep1Valid) || (step === 2 && !isStep2Valid)}
            >
              Next Step
            </Button>
          ) : (
            <Button variant="primary" onClick={handleSubmit}>
              Complete Setup
            </Button>
          )}
        </Stack>
      </Stack>
    </Container>
  );
}
